const stringifyArray = {
  methods: {
    stringifyArray: function(array, key, delim) {
      // if (key) return _.map(array, key).join(delim || ", ");
      // else return array.join(", ");
      if ( !Array.isArray( array ) ) {
        return array || '';
      }
      else {
        if (key) return array.map(function( o ) { return o[ key ]; }).join(delim || ", ");
        else return array.join(", ");
      }
    }
  }
};

const slugify = {
  methods: {
    slugify: function(string) {
      
      if (!string) {
        console.error( 'Failed to slugify string:', 'type:', typeof string, 'string:', string );
        return "";
      }
      
      const a =
        "àáâäæãåāăąçćčđďèéêëēėęěğǵḧîïíīįìłḿñńǹňôöòóœøōõőṕŕřßśšşșťțûüùúūǘůűųẃẍÿýžźż·/_,:;";
      const b =
        "aaaaaaaaaacccddeeeeeeeegghiiiiiilmnnnnoooooooooprrsssssttuuuuuuuuuwxyyzzz------";
      const p = new RegExp(a.split("").join("|"), "g");

      return encodeURIComponent(
        string
          .toString()
          .toLowerCase()
          .replace(/\s+/g, "-") // Replace spaces with -
          .replace(p, c => b.charAt(a.indexOf(c))) // Replace special characters
          .replace(/&/g, "-and-") // Replace & with 'and'
          .replace(/[^\w\-]+/g, "") // Remove all non-word characters
          .replace(/\-\-+/g, "-") // Replace multiple - with single -
          .replace(/^-+/, "") // Trim - from start of text
          .replace(/-+$/, "") // Trim - from end of text
      );
      
    }
  }
};

const makeFullUrl = {
  mixins: [
    slugify,
  ],
  methods: {
    makeFullUrl: function(inputURL) {
      const url = new Url(this.$store.state.urlOrigin + inputURL);
      url.query.ipRedirectOverride = true;
      url.query.overrideBaseCountry = true;
      return url.toString();
    },
    makeUrl: function(type, input, array) {
      const store = this.$store.state;
      const base = this.$store.state.urlOrigin;
      
      let newUrl = "";
      if ( array && !store.sticky.detailLinksToAudible ) {
        const inSubPage = _.get(this.$route, 'meta.subPage');
        const routeSubPage = this.$route.name === 'wishlist' ? 'wishlist' : 'library';
        const subPageSource = inSubPage ? this.$store.state.sticky.subPageSource : routeSubPage;
        switch (type) {
          case "store":
          case "book":
            newUrl = base + "/pd/" + encodeURIComponent(input);
            
            let url = new Url(newUrl);
            url.query.ipRedirectOverride = true;
            url.query.overrideBaseCountry = true;
            newUrl = url.toString();
            break;
          case "author":
            newUrl = { 
              name: 'author', 
              params: { 
                author: input.url || this.slugify(input.name)
              }, 
              query: { 
                subPageSource,
                refresh: true,
              } 
            };
            break;
          case "narrator":
            newUrl = { 
              name: 'narrator', 
              params: { 
                narrator: this.slugify(input.name)
              }, 
              query: { 
                subPageSource,
                refresh: true,
              } 
            };
            break;
          case "series":
            newUrl = { 
              name: 'series', 
              params: { 
                series: input.asin
              }, 
              query: { 
                subPageSource,
                refresh: true,
              } 
            };
            break;
          case "publisher":
            newUrl = { 
              name: 'publisher', 
              params: { 
                publisher: this.slugify(input.name)
              }, 
              query: { 
                subPageSource,
                refresh: true,
              } 
            };
            break;
          case "tags":
            newUrl = { 
              name: subPageSource, 
              query: { 
                filterExtras: `tags:${input.name}`,
                refresh: true,
              } 
            };
            break;
          case "categories":
            
            const cat = {};
            cat.current = _.get(input, 'name');
            cat.currentIndex = _.findIndex( array, { name: cat.current });
            
            const currentIsParent = cat.currentIndex === 0;
            const currentIsChild  = cat.currentIndex === 1;
            cat.parent = currentIsParent ? cat.current : _.get(array, '0.name');
            if ( currentIsParent ) {
              cat.child = undefined;
            }
            else {
              cat.child  = currentIsChild  ? cat.current : _.get(array, '1.name');
            }
            
            newUrl = { 
              name: 'category', 
              params: { 
                parent: cat.parent ? this.slugify(cat.parent) : undefined, 
                child:  cat.child ? this.slugify(cat.child) : undefined, 
              }, 
              query: { 
                subPageSource,
                refresh: true,
              } 
            };
            break;
        }
      }
      else {
        switch (type) {
          case "store":
          case "book":
            newUrl = base + "/pd/" + encodeURIComponent(input);
            break;
          case "author":
            if (input.url) newUrl = base + "/author/" + (input.url || this.slugify(input.name));
            else newUrl = base + "/search?searchAuthor=" + encodeURIComponent(input.name);
            break;
          case "narrator":
            if (input.name) newUrl = base + "/search?searchNarrator=" + encodeURIComponent(input.name);
            break;
          case "series":
            if (input.asin) newUrl = base + "/series/" + input.asin;
            break;
          case "publisher":
            if (input.name) newUrl = base + "/search?searchProvider=" + encodeURIComponent(input.name);
            break;
          case "categories":
          case "tags":
            if (input.url) newUrl = base + "/cat/" + input.url;
            break;
        }
      }
      
      if (!newUrl) {
        return "";
      } 
      else if ( array && !store.sticky.detailLinksToAudible ) {
        return newUrl;
      }
      else {
        let url = new Url(newUrl);
        url.query.ipRedirectOverride = true;
        url.query.overrideBaseCountry = true;
        return url.toString();
      }
      
    }
  }
};

const prepareKeys = {
  methods: {
    prepareKeys: function( config ) {
      
      config = config || {};
      let collection = config.collection || _.get(this.$store.state, this.$store.state.collectionSource);
      // Flattens all available keys into an array: ['title', 'sample'] ...etc
      let keys = _.union(_.flatten(_.map(collection, e => _.keys(e))));

      keys = keys.concat([
        'isbn10', 
        'isbn13'
      ]);

      // Here I make sure these keys get prioritized to the front of the table...
      let priorityKeys = [
        "added",
        "title",
        "series",
        "bookNumbers",
        "authors",
        "narrators",
        "tags",
        "categories",
        "length",
        "progress",
        "releaseDate",
        "publishers",
        "myRating",
        "rating",
        "ratings",
        "favorite",
        "format",
        "language",
        "whispersync",
        "fromPlusCatalog",
        "unavailable",
        "archived",
        "downloaded",
        "storePageChanged",
        "storePageMissing",
      ];
      if ( config.priorityKeys ) priorityKeys = config.priorityKeys;
      let leftoverKeys = _.remove(keys, function(key) {
        return !_.includes(priorityKeys, key);
      });

      keys = priorityKeys.concat(leftoverKeys);
      priorityKeys = null;
      leftoverKeys = null;

      // All the keys we don't want to show in the table
      let removeKeys = [
        "titleShort",
        "sample",
        "blurb",
        "url",
        "summary",
        "moreLikeThis",
        "peopleAlsoBought",
        "asin",
        "cover",
        "sample", // Slipped into titleShort in prepareData() method so they can be in a fixed column together
        "cover", // Same...
        "isbns",
        // "added",
        // "series",
        // "authors",
        // "narrators",
        // "categories",
        // "summary",
        // "length",
        // "progress",
        // "releaseDate",
        // "publishers",
        // "myRating",
        // "rating",
        // "ratings",
        // "downloaded",
        // "format",
        // "language",
        // "favorite",
        // "storePageMissing",
        // "storePageChanged",
      ];
      keys = _.remove(keys, function(key) {
        return !_.includes( (config.removeKeys || removeKeys), key);
      });

      return keys;
    }
  }
};

const makeGoodReadsUrl = {
  methods: {
    makeGoodReadsUrl: function( book ) {
      
      // let isbn10 = _.find( this.book.isbns, { type: "ISBN_10" });
      // if ( isbn10 ) isbn10 = isbn10.identifier
      // let isbn13 = _.find( this.book.isbns, { type: "ISBN_13" });
      // if ( isbn13 ) isbn13 = isbn13.identifier
      book = book || this.book;
      const author = book.authors ? (book.authors[0].name + " - ") : (book.obj && book.obj.authors) ? (book.obj.authors[0].name + " - ") : '';
      let title = (author && book.titleShort ? book.titleShort : book.title) || '';
      const searchQuery = author + title;
      if ( book.titleShort || book.title ) {
        return "https://www.goodreads.com/search?q=" + encodeURIComponent( searchQuery );
      }
      else {
        return null;
      }
      
      // return "https://www.goodreads.com/search?q=" + (isbn10 || isbn13 || encodeURIComponent(authorBook) );
      
    }
  }
};

